  ('Concept',         '529 College Savings Plan','{"529"}',                    'State-sponsored tax-advantaged college savings. Federal tax-free withdrawals for qualified expenses; state-tax deduction varies.',                                                                                                                                                                                  '{}',                                                                                                                                                            0.95, '26 USC § 529'),
  ('Concept',         '529 to Roth Transfer (SECURE 2.0)','{}',                'Lifetime $35k cap; account 15+ years old; subject to annual Roth limits.',                                                                                                                                                                                                                                          '{"lifetime_cap":35000}',                                                                                                                                       0.85, '26 USC § 529'),
  ('Concept',         'FAFSA',                  '{"fafsa"}',                   'Free Application for Federal Student Aid. Required for federal aid + many state/institutional.',                                                                                                                                                                                                                       '{}',                                                                                                                                                            0.95, 'Federal Student Aid'),
