-- ###########################################################################
-- E. HEALTH — expanded
-- ###########################################################################
INSERT INTO central.ontology_entities
  (entity_type, canonical_name, aliases, domain, summary, attributes, source, version, confidence_score, provenance, provenance_id)
SELECT v.entity_type, v.canonical_name, v.aliases::text[], 'health', v.summary, v.attributes::jsonb, 'central_curated_v2', '2', v.confidence,
       jsonb_build_object('source_type', p.source_type, 'source_name', p.source_name, 'source_url', p.source_url, 'citation_reference', p.citation_reference),
       p.id
FROM (VALUES
  -- Nutrition
  ('Concept', 'TDEE (Total Daily Energy Expenditure)','{"tdee"}',        'BMR + thermic effect of food + activity. Foundation for body-composition math.',                                                                                                                                                                                                                              '{}',                                                                                                                                                       0.90, 'DGA 2020-2025'),
  ('Concept', 'BMR (Basal Metabolic Rate)','{"bmr"}',                    'Calories burned at rest. Mifflin-St Jeor equation widely used.',                                                                                                                                                                                                                                                '{}',                                                                                                                                                       0.90, 'DGA 2020-2025'),
  ('Concept', 'Macronutrient Distribution Range','{"amdr"}',             'USDA AMDR: 45-65% carbs, 20-35% fat, 10-35% protein.',                                                                                                                                                                                                                                                          '{"carbs_pct":"45-65","fat_pct":"20-35","protein_pct":"10-35"}',                                                                                          0.90, 'DGA 2020-2025'),
  ('Concept', 'Time-Restricted Eating (TRE)','{"tre","if"}',             '8-12h daily eating window. Equivocal evidence beyond calorie matching.',                                                                                                                                                                                                                                            '{}',                                                                                                                                                       0.70, 'PMID: 35044835'),
  ('Concept', 'Glycemic Load',                '{}',                       'GI × carb-g/100. Better predictor of post-prandial response than GI alone.',                                                                                                                                                                                                                                          '{}',                                                                                                                                                       0.80, 'DGA 2020-2025'),
  ('Concept', 'DASH Eating Pattern',          '{"dash"}',                 'Dietary Approaches to Stop Hypertension. Reduces systolic BP 8-14 mmHg in clinical trials.',                                                                                                                                                                                                                          '{}',                                                                                                                                                       0.90, 'AHA 2024'),
  ('Concept', 'Whole-Food Plant-Forward',      '{"plant-forward"}',       'Pattern emphasizing minimally processed plants; PURE-class cohort: lower CV mortality.',                                                                                                                                                                                                                                '{}',                                                                                                                                                       0.85, 'DGA 2020-2025'),
  ('Concept', 'Fiber Target (28-38g/day)',     '{}',                      'Adult fiber recommendation. Most Americans consume ~15g.',                                                                                                                                                                                                                                                          '{"target_g_per_day":"28-38"}',                                                                                                                              0.90, 'DGA 2020-2025'),
  -- Exercise science
  ('Concept', 'Periodization (Linear)',        '{}',                      'Progressive overload phase blocks: hypertrophy → strength → power. Classic strength model.',                                                                                                                                                                                                                            '{}',                                                                                                                                                       0.85, 'ACSM PAG'),
  ('Concept', 'Periodization (Block)',         '{}',                      'Specialized training blocks (volume / intensity / taper). Common in track + Olympic lifting.',                                                                                                                                                                                                                          '{}',                                                                                                                                                       0.80, 'ACSM PAG'),
  ('Concept', 'Periodization (Conjugate)',     '{}',                      'Concurrent strength + speed + max-effort method (Westside Barbell).',                                                                                                                                                                                                                                                  '{}',                                                                                                                                                       0.70, 'ACSM PAG'),
  ('Concept', 'High-Intensity Interval Training','{"hiit"}',              'Short maximal-effort bouts. Time-efficient cardio gain; not a substitute for total weekly volume.',                                                                                                                                                                                                                    '{}',                                                                                                                                                       0.85, 'ACSM PAG'),
  ('Concept', 'Concurrent Training Interference Effect','{"concurrent"}', 'Heavy endurance + strength same session blunts strength gain modestly. Separate sessions when possible.',                                                                                                                                                                                                                '{}',                                                                                                                                                       0.80, 'PMID: 35001643'),
  ('Concept', 'Plyometric Training',           '{}',                      'Power development via stretch-shortening cycle. Adds explosiveness; injury risk elevated without prep.',                                                                                                                                                                                                                  '{}',                                                                                                                                                       0.80, 'ACSM PAG'),
  -- Recovery / sleep
  ('Concept', 'Sleep Efficiency',              '{}',                      'Time asleep / time in bed. 85%+ healthy adult target.',                                                                                                                                                                                                                                                                  '{"target_pct":"85+"}',                                                                                                                                      0.85, 'AASM Practice Standards'),
  ('Concept', 'REM Sleep Importance',          '{}',                      'Memory consolidation + emotional regulation. Suppressed by alcohol + late-window food.',                                                                                                                                                                                                                                  '{}',                                                                                                                                                       0.85, 'AASM Practice Standards'),
  ('Concept', 'Slow-Wave Sleep (Deep)',        '{"sws","n3"}',            'Growth hormone release + physical recovery. Most concentrated in first half of night.',                                                                                                                                                                                                                                  '{}',                                                                                                                                                       0.85, 'AASM Practice Standards'),
  ('Concept', 'Circadian Misalignment',        '{}',                      'Shift work + late-night eating disrupt cortisol/melatonin cycle. Drives insulin resistance.',                                                                                                                                                                                                                              '{}',                                                                                                                                                       0.85, 'AASM Practice Standards'),
  ('Concept', 'Active Recovery',               '{}',                      'Light activity (walk, swim, mobility) post-hard session. Speeds clearance + maintains adherence.',                                                                                                                                                                                                                        '{}',                                                                                                                                                       0.80, 'ACSM PAG'),
  ('Concept', 'Massage / Soft-Tissue Work',    '{}',                      'Acute DOMS reduction; chronic strength/performance gain marginal. Behavioral adherence value.',                                                                                                                                                                                                                            '{}',                                                                                                                                                       0.65, 'ACSM PAG'),
  -- Behavior change frameworks
  ('Concept', 'Stages of Change Model',        '{"transtheoretical"}',    'Prochaska/DiClemente: precontemplation → contemplation → preparation → action → maintenance.',                                                                                                                                                                                                                              '{}',                                                                                                                                                       0.75, 'Atomic Habits (ISBN 978-0735211292)'),
  ('Concept', 'Tiny Habits (Fogg)',            '{"fogg"}',                'Anchor behavior + minimal commitment + celebration. High-friction → low-friction designs.',                                                                                                                                                                                                                                '{}',                                                                                                                                                       0.70, 'Atomic Habits (ISBN 978-0735211292)'),
  ('Concept', 'Implementation Intentions',     '{"if-then plans"}',       '"When X happens I will do Y." Doubles follow-through per Gollwitzer meta-analyses.',                                                                                                                                                                                                                                      '{}',                                                                                                                                                       0.80, 'Atomic Habits (ISBN 978-0735211292)'),
  ('Concept', 'Identity-Based Habit',          '{}',                      '"I am a runner" outperforms "I run." Self-perception drives sustained behavior.',                                                                                                                                                                                                                                          '{}',                                                                                                                                                       0.65, 'Atomic Habits (ISBN 978-0735211292)'),
  ('Concept', 'Environment Design',            '{}',                      'Make desired behavior the path of least resistance; hide cues for undesired.',                                                                                                                                                                                                                                            '{}',                                                                                                                                                       0.70, 'Atomic Habits (ISBN 978-0735211292)')
) AS v(entity_type, canonical_name, aliases, summary, attributes, confidence, citation)
JOIN central.provenance_records p ON p.citation_reference = v.citation
ON CONFLICT (entity_type, lower(canonical_name)) DO NOTHING;


