  ('Survivors'' & Dependents'' Education Assistance Chapter 35','Bachelor''s Degree (Generic)','SUPPORTS',0.6,0.9,'VA Post-9/11 GI Bill'),
  ('VA Specially Adapted Housing (SAH) Grant','Home Ownership','SUPPORTS',0.7,0.9,'VA Disability'),
  ('Service-Disabled Veteran Insurance (S-DVI)','Term Life Insurance — 20-year level','SUPPORTS',0.5,0.85,'VA Disability'),
