-- ###########################################################################
-- H. Self-test — assert each domain GREW.
-- ###########################################################################
DO $$
DECLARE
  d TEXT;
  c BIGINT;
  v_under TEXT[] := ARRAY[]::TEXT[];
BEGIN
  FOREACH d IN ARRAY ARRAY['finance','career','education','health','estate_planning','military_veteran']
  LOOP
    SELECT COUNT(*) INTO c
      FROM central.ontology_entities
     WHERE domain = d AND review_status = 'approved' AND source LIKE 'central_curated_v%';
    IF c < 15 THEN
      v_under := array_append(v_under, format('%s=%s', d, c));
    END IF;
  END LOOP;
  IF array_length(v_under, 1) IS NOT NULL THEN
    RAISE EXCEPTION '083 self-test: domains under v2 entity-count threshold: %', v_under;
  END IF;
END $$;
